mapper.select:
select  user_id, user_drug_id1, user_drug_id2, drug_id1, drug_id2,
            drug_name1, drug_name2, severity_level, show_status, update_time
from kh_user_drug_interaction
where user_id = #{userId,jdbcType=BIGINT}
    and user_drug_id1 = #{userDrugId1,jdbcType=BIGINT}
    and user_drug_id2 = #{userDrugId2,jdbcType=BIGINT}

mapper.update:
update kh_user_drug_interaction
set show_status = #{showStatus,jdbcType=SMALLINT},
update_time = now()
where user_id = #{userId,jdbcType=BIGINT}
        and (user_drug_id1 = #{userDrugId,jdbcType=BIGINT}
                or user_drug_id2 = #{userDrugId,jdbcType=BIGINT})

